INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('             
                               
                             
     Em tudo o que não se encontre regulado no presente decreto-lei, aplica-se a legislação vigente para os trabalhadores com vínculo de emprego público na modalidade de contrato de trabalho em funções públicas por tempo indeterminado.            
         
   
     
                         
                          
  Artigo 48.º 
Norma revogatória
                            
                           
                             
                               
                             
     São revogados:
  a) Os artigos 21.º, 23.º a 33.º, 35.º, 40.º a 42.º, 44.º, 46.º a 50.º, 76.º, 88.º a 91.º e 94.º do Decreto-Lei n.º 519-F2/79, de 29 de dezembro, na sua redação atual;
  b) O Decreto-Lei n.º 92/90, de 17 de março, na sua redação atual;
  c) O Decreto-Lei n.º 206/97, de 12 de agosto, na sua redação atual;
  d) Os artigos 49.º a 51.º, 53.º a 56.º, 59.º, 60.º, 62.º a 66.º, 68.º, 80.º a 92.º, 94.º a 98.º, 100.º a 111.º, 114.º a 116.º e 143.º do Decreto Regulamentar n.º 55/80, de 8 de outubro, na sua redação atual.            
         
   
     
                         
                          
  Artigo 49.º 
Produção de efeitos
                            
                           
                             
                               
                             
     O presente decreto-lei produz efeitos a 1 de janeiro de 2018.
  
  Visto e aprovado em Conselho de Ministros de 15 de novembro de 2018. - António Luís Santos da Costa - Maria de Fátima de Jesus Fonseca - Francisca Eugénia da Silva Dias Van Dunem.
  Promulgado em 12 de dezembro de 2018.
  Publique-se.
  O Presidente da República, Marcelo Rebelo de Sousa.
  Referendado em 17 de dezembro de 2018.
  Pelo Primeiro-Ministro, Augusto Ernesto Santos Silva, Ministro dos Negócios Estrangeiros.','33');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:5  
    
  DL n.º 323/2001, de 17 de Dezembro  (versão actualizada) CONVERSÃO P/O EURO NA LEGISLAÇÃO DA ÁREA DA JUSTIÇA    
    
 
  
                         
                          
SUMÁRIOProcede à conversão de valores expressos em escudos para euros em legislação da área da justiça
A futura utilização em exclusivo do euro como moeda em território nacional, estabelecida progressivamente até 1 de Março de 2002, substituindo o uso do escudo, obriga a uma especial atenção quando estão em causa valores constantes de textos legais. 
  A necessidade de manter a segurança e certeza jurídicas no processo de transição para a adopção plena do euro leva a que se entenda proceder à conversão dos valores expressos em escudos em legislação da área da justiça, por forma a facilitar a utilização dos textos legais e reduzir ao mínimo as dificuldades inerentes ao processo de substituição da moeda. 
  Assim:
  Nos termos da alínea a) do n.º 1 do artigo 198.º da Constituição, o Governo decreta, para valer como lei geral da República, o seguinte:  Artigo 1.º Objecto
                            
                           
                             
                               
                             
     1 - Os valores fixados em escudos nos diplomas referidos no anexo que integra o presente decreto-lei são convertidos em euros. 
  2 - É aplicada, automaticamente, a taxa de conversão em euros prevista no artigo 1.º do Regulamento CE n.º 2866/98, do Conselho, a todas as referências feitas a escudos em actos na área da justiça não previstos no anexo que integra o presente diploma.            
         
   
     
                         
                          
  Artigo 2.º Norma transitória
                            
                           
                             
                               
                             
     As alterações constantes do presente diploma não prejudicam os direitos das partes em acções propostas anteriormente à sua entrada em vigor.            
         
   
     
                         
                          
  Artigo 3.º Valor da unidade de conta processual
                            
                           
                             
                               
                             
     A partir de 1 de Janeiro de 2002 a unidade de conta processual tem o valor de (euro) 79,81.            
         
   
     
                         
                          
  Artigo 4.º Entrada em vigor
                            
                           
                             
                               
                             
     O presente diploma entra em vigor no dia 1 de Janeiro de 2002.
  
  Visto e aprovado em Conselho de Ministros de 15 de Novembro de 2001. - Guilherme d''Oliveira Martins - Guilherme d''Oliveira Martins - Henrique Nuno Pires Severiano Teixeira - António Luís Santos Costa. 
  
  Promulgado em 5 de Dezembro de 2001.
  Publiqu','33');
